// Cambiar texto y estilo
const h1 = document.querySelector('h1');
h1.textContent = 'Bienvenido a JavaScript';
h1.style.color = '#2563eb';
h1.style.fontWeight = 'bold';

// Manejar clases — forma preferida en proyectos reales
const menu = document.querySelector('.menu');

// Mostrar/ocultar con una clase CSS
menu.classList.add('visible');    // muestra el menú
menu.classList.remove('visible'); // oculta el menú
menu.classList.toggle('visible'); // alterna

console.log(menu.classList.contains('visible')); // true o false

// Crear elementos dinámicamente
const lista = document.querySelector('ul');

const frutas = ['Manzana', 'Banana', 'Naranja'];

frutas.forEach(fruta => {
  const li = document.createElement('li');
  li.textContent = fruta;
  lista.appendChild(li); // agrega cada <li> a la <ul>
});

